const email = $input.item.json;
const subject = email.subject || email.Subject || '';
let from = email.from || email.From || '';
if (from && typeof from === 'object') from = (from.value && from.value[0] && from.value[0].address) || from.address || from.text || '';
from = String(from || 'unknown');

function b64urlDecode(data) {
  try { return Buffer.from(String(data || '').replace(/-/g, '+').replace(/_/g, '/'), 'base64').toString('utf-8'); }
  catch (e) { return ''; }
}
function extractBody(payload) {
  let text = '', html = '';
  (function walk(part) {
    if (!part) return;
    const mime = part.mimeType || '';
    if (mime === 'text/plain' && part.body && part.body.data) text += b64urlDecode(part.body.data);
    else if (mime === 'text/html' && part.body && part.body.data) html += b64urlDecode(part.body.data);
    if (Array.isArray(part.parts)) part.parts.forEach(walk);
  })(payload);
  return { text: text, html: html };
}

let body = email.text || '';
let htmlSrc = email.html || '';
if (!body && !htmlSrc && email.payload) { const d = extractBody(email.payload); body = d.text || ''; htmlSrc = d.html || ''; }
if (!body && htmlSrc) {
  body = htmlSrc
    .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, ' ')
    .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<').replace(/&gt;/g, '>')
    .replace(/&#39;/g, "'").replace(/&quot;/g, '"')
    .replace(/\s+/g, ' ').trim();
}
if (!body) body = email.snippet || '';
const bodyTruncated = body.substring(0, 6000);

const sys = 'Tu es un extracteur d offres d emploi. Tu lis un email d alerte emploi et extrais toutes les offres qu il contient. Reponds UNIQUEMENT avec un JSON valide.';
const usr = 'Email recu.\nDe: ' + from + '\nSujet: ' + subject + '\n\nContenu:\n' + bodyTruncated + '\n\nExtrais toutes les offres d emploi presentes. Format de reponse: un objet JSON avec une cle jobs qui est un tableau. Chaque element a les cles title, company, location, url, desc. Si aucune offre, renvoie jobs avec tableau vide.';

const msgs = [
  { role: 'system', content: sys },
  { role: 'user', content: usr }
];
const opts = { temperature: 0.2 };
const requestBody = { model: $env.VEILLE_EXTRACT_MODEL_CLOUD, messages: msgs, stream: false, format: 'json', options: opts };

const out = { requestBody: requestBody, emailId: email.id, emailFrom: from, emailSubject: subject, bodyLen: body.length };
return { json: out };

const responses = $input.all();
const requests = $('Build Extract Request').all();
const allJobs = [];

for (let i = 0; i < responses.length; i++) {
  const resp = responses[i].json;
  const req = requests[i] ? requests[i].json : {};
  const emailFrom = req.emailFrom || 'unknown';

  let jobs = [];
  try {
    let content = resp.message && resp.message.content ? resp.message.content : '';
    if (typeof content === 'string') {
      content = content.replace(/^\s*```(?:json)?\s*/i, '').replace(/\s*```\s*$/, '').trim();
      const m = content.match(/\{[\s\S]*\}/);
      if (m) content = m[0];
    }
    const parsed = typeof content === 'string' ? JSON.parse(content) : content;
    jobs = parsed.jobs || [];
  } catch (e) {
    jobs = [];
  }

  let source = 'Email';
  const f = emailFrom.toLowerCase();
  if (f.indexOf('linkedin') >= 0) source = 'LinkedIn';
  else if (f.indexOf('welcometothejungle') >= 0) source = 'WTTJ';
  else if (f.indexOf('web3.career') >= 0) source = 'Web3.career';
  else if (f.indexOf('cryptocareers') >= 0) source = 'CryptoCareers';
  else if (f.indexOf('trueup') >= 0) source = 'TrueUp';
  else if (f.indexOf('remote3') >= 0) source = 'Remote3';

  for (const j of jobs) {
    const descStr = j.desc || '';
    allJobs.push({
      title: j.title || '',
      company: j.company || '',
      location: j.location || 'Remote',
      url: j.url || '',
      desc: descStr.substring(0, 500),
      source: source,
      date: '',
      cat: '',
      tags: '',
      salary: ''
    });
  }
}

return allJobs.map(j => ({ json: j }));

const jobs = $input.all().map(i => i.json);
const INCLUDE = ["account executive", "enterprise account executive", "strategic account executive", "mid-market account executive", "smb account executive", "account manager", "key account manager", "named account manager", "strategic account manager", "account director", "account management", "revenue operations", "revops", "rev ops", "sales operations", "sales ops", "gtm operations", "gtm ops", "go-to-market operations", "growth operations", "growth ops", "outbound sales", "outbound operations", "business development", "business developer", "partnerships", "partner manager", "alliances", "customer success manager", "sales manager", "ingenieur d'affaires", "charge d'affaires", "charge de developpement commercial", "responsable grands comptes", "responsable comptes cles", "gestionnaire grands comptes"];
const EXCLUDE = ["head of sales", "vp sales", "vp of sales", "vice president of sales", "svp sales", "chief revenue officer", "chief sales officer", "directeur commercial", "directrice commerciale", "directeur des ventes", "sales director", "technico-commercial", "technico commercial", "commercial terrain", "commercial sedentaire", "commercial itinerant", "vendeur", "vendeuse", "televente", "teleconseiller", "teleprospecteur", "porte-a-porte", "vrp", "agent commercial", "agent general", "assurance", "assureur", "mutuelle", "prevoyance", "courtier", "immobilier", "btp", "batiment", "menuiserie", "fenetre", "isolation", "photovoltaique", "panneaux solaires", "automobile", "concession", "grande distribution", "pompes funebres", "sales engineer", "sales engineering", "presales", "pre-sales", "avant-vente", "sales development", "sdr", "salesforce", "recruteur", "recruitment", "talent acquisition", "stage", "alternance", "apprentissage", "stagiaire"];
const L = ["remote", "fully remote", "full remote", "remote-first", "remote france", "remote europe", "eu remote", "wfh", "work from home", "distributed", "anywhere", "worldwide", "teletravail", "distanciel", "hybrid", "hybride", "france", "nantes", "toulouse", "lyon", "paris", "bordeaux", "lille", "rennes", "nice", "montpellier", "marseille", "strasbourg", "nouvelle-aquitaine", "ile-de-france", "europe", "emea", "global"];
const VAGUE_LOC = ['', 'unknown', 'not specified', 'n/a', 'na', 'none', '?', '-'];
const deburr = s => (s || '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');

const filtered = (typeof allJobs !== 'undefined' ? allJobs : jobs).filter(j => {
  const title = deburr(j.title);
  const hay = deburr((j.title || '') + ' ' + (j.desc || ''));
  if (EXCLUDE.some(k => title.indexOf(k) >= 0)) return false;
  const roleMatch = INCLUDE.some(k => title.indexOf(k) >= 0);
  const loc = deburr(j.location).trim();
  const locationMatch = L.some(k => loc.indexOf(k) >= 0) || VAGUE_LOC.indexOf(loc) >= 0;
  return roleMatch && locationMatch;
});

const seen = new Set();
const unique = filtered.filter(j => {
  const k = (j.title + '_' + j.company).toLowerCase();
  if (seen.has(k)) return false;
  seen.add(k);
  return true;
});

return unique.map(j => ({ json: j }));

const jobs = $input.all().map(i => i.json);
const MAX = parseInt($env.VEILLE_BATCH_MAX, 10) || 40;
const batch = jobs.slice(0, MAX);

let jobsText = '';
for (let i = 0; i < batch.length; i++) {
  const j = batch[i];
  jobsText += (i+1) + '. ' + j.title + ' @ ' + j.company + ' (' + j.location + ')\n';
  jobsText += 'Source: ' + j.source + ' | URL: ' + j.url + '\n';
  jobsText += 'Desc: ' + (j.desc || '').substring(0, 300) + '\n\n';
}

const sys = 'Tu es un assistant de veille emploi pour un candidat base a Bordeaux, qui recherche surtout du REMOTE. Profil cible: Account Executive, Account Manager / Key Account, Revenue Operations, Sales Ops, GTM Ops, Outbound/Growth Ops, Business Development. Secteurs prioritaires: crypto-fintech, foodtech, AI, SaaS. NON cible (score bas): postes trop seniors (Head of Sales, VP, Director), technico-commercial, assurance, BTP, vente terrain. Score chaque offre 0-10 selon pertinence. Reponds UNIQUEMENT avec un JSON valide, aucun texte autour.';

const usr = 'Voici ' + batch.length + ' offres issues d alertes email. Pour chaque offre, donne un score (0-10), une raison courte (max 15 mots) et une classe (top si >=7, watch si 4-6, skip si <4).\n\nFormat de reponse: un objet JSON avec une cle scores qui est un tableau. Chaque element a les cles n, score, class, reason.\n\nOffres:\n' + jobsText;

const msgs = [
  { role: 'system', content: sys },
  { role: 'user', content: usr }
];
const opts = { temperature: 0 };
const requestBody = { model: $env.VEILLE_SCORE_MODEL_LOCAL, messages: msgs, stream: false, format: 'json', options: opts };

const out = { requestBody: requestBody, jobs: batch, jobsCount: batch.length };
return [{ json: out }];

const llm = $input.first().json;
const preparedJobs = $('Prepare Scoring').first().json.jobs || [];

const TO_EMAIL = $env.VEILLE_TO_EMAIL;

function esc(s) {
  return String(s == null ? '' : s)
    .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

let scores = [];
try {
  const content = llm.message && llm.message.content ? llm.message.content : '';
  const parsed = typeof content === 'string' ? JSON.parse(content) : content;
  scores = parsed.scores || [];
} catch (e) { scores = []; }

const scored = preparedJobs.map((j, i) => {
  const found = scores.find(x => Number(x.n) === (i+1));
  const score = found ? (found.score || 0) : 0;
  const klass = found ? (found.class || 'skip') : 'skip';
  const reason = found ? (found.reason || '') : 'non score';
  return Object.assign({}, j, { score: score, klass: klass, reason: reason });
});

const top = scored.filter(j => j.klass === 'top').sort((a,b) => b.score - a.score);
const watch = scored.filter(j => j.klass === 'watch').sort((a,b) => b.score - a.score);

const today = new Date().toISOString().substring(0, 10);

// --- Markdown (for file Save Digest) ---
let md = '# Veille Emploi Emails — ' + today + '\n\n';
md += '_' + scored.length + ' offres extraites — ' + top.length + ' top, ' + watch.length + ' a suivre_\n\n';
md += '## Top (score >= 7)\n\n';
if (top.length === 0) md += '_Aucune offre top aujourd hui._\n\n';
for (const j of top) {
  md += '### [' + j.score + '/10] ' + j.title + ' — ' + j.company + '\n';
  md += '- Location: ' + j.location + '\n';
  md += '- Source: ' + j.source + '\n';
  md += '- URL: ' + j.url + '\n';
  md += '- Raison: ' + j.reason + '\n';
  if (j.salary) md += '- Salary: ' + j.salary + '\n';
  md += '\n';
}
md += '## A suivre (4-6)\n\n';
if (watch.length === 0) md += '_Aucune offre a suivre._\n\n';
for (const j of watch) {
  md += '- [' + j.score + '/10] [' + j.title + '](' + j.url + ') @ ' + j.company + ' — ' + j.location + ' — _' + j.reason + '_\n';
}

// --- HTML (for email) ---
function jobCard(j) {
  const badge = '<span style="display:inline-block;background:#0969da;color:#fff;border-radius:4px;padding:2px 8px;font-size:12px;font-weight:600;">' + j.score + '/10</span>';
  return '<div style="border:1px solid #e1e4e8;border-radius:6px;padding:12px;margin:8px 0;">'
    + '<div style="font-size:15px;font-weight:600;">' + badge + ' ' + esc(j.title) + ' — ' + esc(j.company) + '</div>'
    + '<div style="font-size:13px;color:#57606a;margin-top:4px;">' + esc(j.location) + ' · ' + esc(j.source) + '</div>'
    + '<div style="font-size:13px;margin-top:6px;"><a href="' + esc(j.url) + '" style="color:#0969da;text-decoration:none;">Voir l\'offre →</a></div>'
    + '<div style="font-size:13px;color:#24292f;margin-top:6px;"><em>' + esc(j.reason) + '</em></div>'
    + '</div>';
}
function watchLine(j) {
  return '<li style="font-size:13px;margin:4px 0;"><strong>[' + j.score + '/10]</strong> <a href="' + esc(j.url) + '" style="color:#0969da;">' + esc(j.title) + '</a> @ ' + esc(j.company) + ' — ' + esc(j.location) + ' — <em>' + esc(j.reason) + '</em></li>';
}

let inner = '<p style="font-size:14px;color:#57606a;">' + scored.length + ' offres extraites — ' + top.length + ' top, ' + watch.length + ' a suivre.</p>';
inner += '<h2 style="font-size:16px;margin-top:24px;">Top (score &gt;= 7)</h2>';
if (top.length === 0) inner += '<p style="font-size:13px;color:#6a737d;"><em>Aucune offre top aujourd hui.</em></p>';
else inner += top.map(jobCard).join('');
inner += '<h2 style="font-size:16px;margin-top:24px;">A suivre (4-6)</h2>';
if (watch.length === 0) inner += '<p style="font-size:13px;color:#6a737d;"><em>Aucune offre a suivre.</em></p>';
else inner += '<ul style="padding-left:20px;">' + watch.map(watchLine).join('') + '</ul>';

const html = '<!doctype html><html><body style="margin:0;padding:0;background:#f6f7f9;font-family:-apple-system,Segoe UI,Roboto,Helvetica,Arial,sans-serif;color:#1f2328;">'
  + '<div style="max-width:680px;margin:0 auto;padding:24px;">'
  + '<h1 style="font-size:20px;margin:0 0 16px;">Veille Emploi Emails — ' + today + '</h1>'
  + inner
  + '<hr style="border:0;border-top:1px solid #e1e4e8;margin:24px 0;">'
  + '<div style="font-size:12px;color:#6a737d;">Veille Emploi · alertes plateformes · ' + esc(today) + '</div>'
  + '</div></body></html>';

const subject = '[Veille] Email Alerts ' + today + ' — ' + top.length + ' top, ' + watch.length + ' a suivre';

const filePath = $env.VEILLE_OUTPUT_DIR + '/emails/' + today + '.md';
const base64 = Buffer.from(md, 'utf-8').toString('base64');

return [{
  json: {
    filePath: filePath, count: scored.length, topCount: top.length, watchCount: watch.length,
    to: TO_EMAIL, subject: subject, html: html
  },
  binary: { data: { data: base64, mimeType: 'text/markdown', fileName: today + '.md', fileExtension: 'md' } }
}];
